<script lang="ts">
  import { onMount } from 'svelte';
  import { goto } from '$app/navigation';
  import { page } from '$app/state';
  import { Button, Modal, Spinner } from 'flowbite-svelte';
  import ImportNotice from '$lib/components/admin/ImportNotice.svelte';
  import ImportWizardStepper from '$lib/components/admin/ImportWizardStepper.svelte';
  import { commitImportSession, getImportSession, listAllImportSessionItems, retryFailedImportSession, type ImportSession, type ImportSessionItem } from '$lib/api/imports';
  const card = 'rounded-2xl border border-slate-800 bg-[#151a26] p-5 shadow-xl shadow-black/15 sm:p-6';
  const sessionId = $derived(page.params.sessionId ?? '');
  let session = $state<ImportSession | null>(null); let items = $state<ImportSessionItem[]>([]); let loading = $state(false); let busy = $state(false); let error = $state<string | null>(null); let notice = $state<string | null>(null); let confirmOpen = $state(false); let completeOpen = $state(false); let timer: ReturnType<typeof setTimeout> | undefined; let completionHandled = $state(false);
  const total = $derived(items.length); const done = $derived(items.filter((x) => ['imported', 'alreadyImported', 'failed'].includes(x.status)).length); const overall = $derived(total ? Math.round(done / total * 100) : 0); const terminal = $derived(session?.status === 'completed' || session?.status === 'completedWithFailures'); const visible = $derived(terminal ? items.filter((x) => x.status === 'failed') : items);
  onMount(() => { void load(); return () => { if (timer) clearTimeout(timer); }; });
  async function load() { loading = true; error = null; try { [session, items] = await Promise.all([getImportSession(sessionId), listAllImportSessionItems(sessionId, { included: true })]); if (session.status === 'committing') timer = setTimeout(() => void load(), 1500); if (session.status === 'completed' && !completionHandled) { completionHandled = true; completeOpen = true; } } catch (err) { error = err instanceof Error ? err.message : 'Could not load import progress.'; } finally { loading = false; } }
  async function start() { confirmOpen = false; busy = true; error = null; notice = null; try { const response = await commitImportSession(sessionId); session = response.session ?? session; notice = `Import started for ${response.approvedCount} file${response.approvedCount === 1 ? '' : 's'}.`; await load(); } catch (err) { error = err instanceof Error ? err.message : 'Could not start the import.'; } finally { busy = false; } }
  async function retry() { busy = true; error = null; try { const response = await retryFailedImportSession(sessionId); session = response.session ?? session; notice = `${response.resetCount} failed file${response.resetCount === 1 ? '' : 's'} restarted.`; await load(); } catch (err) { error = err instanceof Error ? err.message : 'Could not retry failed files.'; } finally { busy = false; } }
  function progress(item: ImportSessionItem) { const values: Record<string, number> = { discovered: 0, probed: 5, approved: 10, hashing: 25, uploading: 60, finalizing: 85, imported: 100, alreadyImported: 100, failed: 100 }; return values[item.status] ?? 0; }
  function statusText(item: ImportSessionItem) { if (item.status === 'alreadyImported') return 'Already imported'; if (item.status === 'imported') return 'Imported'; if (item.status === 'failed') return 'Failed'; return item.status.charAt(0).toUpperCase() + item.status.slice(1); }
</script>

<ImportWizardStepper current={6} {sessionId} />
<section class={card}>
  <div class="flex flex-wrap items-start gap-4"><div><h1 class="text-xl font-bold text-white">Import media</h1><p class="mt-2 text-sm text-slate-400">Start the import, then leave this page open to monitor each file.</p></div>{#if session?.status === 'reviewing'}<Button color="blue" size="lg" class="ml-auto border-0! px-8! py-3! text-base! font-bold!" disabled={busy || !items.length} onclick={() => (confirmOpen = true)}>Start import</Button>{/if}{#if session?.status === 'completedWithFailures'}<Button color="red" class="ml-auto font-semibold!" disabled={busy} onclick={retry}>Retry failed imports</Button>{/if}</div>
  <div class="mt-5"><ImportNotice {error} {notice} /></div>
  <div class="mb-5 rounded-xl border border-slate-800 bg-slate-950/30 p-4"><div class="mb-2 flex justify-between text-sm"><span class="font-semibold text-slate-300">Overall progress</span><span class="text-slate-400">{done} / {total}</span></div><div class="h-3 overflow-hidden rounded-full bg-slate-800"><div class="h-full rounded-full bg-blue-500 transition-all duration-500" style={`width: ${overall}%`}></div></div></div>
  {#if loading && !items.length}<div class="flex items-center gap-2 p-8 text-sm text-slate-400"><Spinner size="4" />Loading files…</div>{:else}<div class="space-y-3">{#each visible as item (item.itemId)}<details class={`rounded-xl border p-4 ${item.status === 'failed' ? 'border-red-900/70 bg-red-950/15' : 'border-slate-800 bg-slate-950/25'}`}><summary class="cursor-pointer list-none"><div class="flex items-center gap-3"><span class={`text-lg ${item.status === 'failed' ? 'text-red-400' : item.status === 'imported' || item.status === 'alreadyImported' ? 'text-emerald-400' : 'text-slate-500'}`}>{item.status === 'failed' ? '✕' : item.status === 'imported' || item.status === 'alreadyImported' ? '✓' : '○'}</span><div class="min-w-0 flex-1"><div class="flex justify-between gap-3"><p class="truncate text-sm font-medium text-slate-200">{item.title || item.fileName}</p><span class="shrink-0 text-xs text-slate-400">{statusText(item)}</span></div><div class="mt-2 h-1.5 overflow-hidden rounded-full bg-slate-800"><div class={`h-full transition-all ${item.status === 'failed' ? 'bg-red-500' : 'bg-blue-500'}`} style={`width: ${progress(item)}%`}></div></div></div></div></summary><div class="mt-3 border-t border-slate-800 pt-3 text-xs text-slate-500"><p title={item.relativePath}>{item.relativePath}</p><p class="mt-1">Attempt {Math.max(1, item.attempt + 1)} · {item.errorMessage || statusText(item)}</p></div></details>{:else}<div class="rounded-xl border border-dashed border-slate-800 p-10 text-center text-sm text-slate-500">{terminal ? 'All completed files have been cleared from this list.' : 'No files selected.'}</div>{/each}</div>{/if}
  <div class="mt-6"><a class="rounded-lg px-4 py-2.5 text-sm font-semibold text-slate-400 hover:text-white" href={`/admin/import/${sessionId}/review`}>Back to review</a></div>
</section>

<Modal bind:open={confirmOpen} title="Ready to start the import?" size="md" class="z-50"><p class="text-sm leading-6 text-slate-400">FrostStream will copy {items.length} selected file{items.length === 1 ? '' : 's'} to <span class="font-mono text-slate-200">{session?.storageKey}</span>. A failure will be isolated to that file and the rest will continue.</p>{#snippet footer()}<div class="flex w-full justify-end gap-2"><Button color="dark" class="border-slate-700! bg-transparent!" onclick={() => (confirmOpen = false)}>Not yet</Button><Button color="blue" class="border-0! font-semibold!" onclick={start}>Start import</Button></div>{/snippet}</Modal>
<Modal bind:open={completeOpen} title="Import Complete" size="md" class="z-50"><div class="py-3 text-center"><div class="mx-auto flex h-14 w-14 items-center justify-center rounded-full bg-emerald-950 text-2xl text-emerald-400">✓</div><p class="mt-4 text-sm text-slate-300">All {items.length} files imported successfully.</p></div>{#snippet footer()}<div class="flex w-full justify-end"><Button color="blue" class="border-0!" onclick={() => goto('/')}>Return home</Button></div>{/snippet}</Modal>
